    const uint32_t N  = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    const uint32_t Ci = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    const uint32_t Hi = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    const uint32_t Wi = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3));

    const uint32_t Co = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0));
    const uint32_t Kh = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(2));
    const uint32_t Kw = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(3));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *strideH = attrs->GetAttrPointer<int32_t>(0);
    const int32_t *strideW = attrs->GetAttrPointer<int32_t>(1);
    const int32_t *padTop  = attrs->GetAttrPointer<int32_t>(2);
    const int32_t *padLeft = attrs->GetAttrPointer<int32_t>(3);

    const uint32_t sH = static_cast<uint32_t>(*strideH);
    const uint32_t sW = static_cast<uint32_t>(*strideW);
    const uint32_t pT = static_cast<uint32_t>(*padTop);
    const uint32_t pL = static_cast<uint32_t>(*padLeft);

    // Only support stride=1, pad=0 in this kernel implementation
    if (sH != 1 || sW != 1 || (pT != 0) || (pL != 0)) {
        return ge::GRAPH_FAILED;
    }

    // Output shape (no padding)
    const uint32_t Ho = (Hi + 2 * pT - Kh) / sH + 1;
    const uint32_t Wo = (Wi + 2 * pL - Kw) / sW + 1;

    // Tile: process one output row (Wo elements) per tile to ensure contiguous DMA
    const uint32_t tileW = Wo;

    // Map each tile to a (n, ho) row
    uint32_t numTiles = N * Ho;
    uint32_t blockDim = numTiles;
    if (blockDim == 0) blockDim = 1u;
    if (blockDim > 24u) blockDim = 24u;  // conservative

    context->SetBlockDim(blockDim);

    tiling.set_N(N);
    tiling.set_Ci(Ci);
    tiling.set_Hi(Hi);
    tiling.set_Wi(Wi);
    tiling.set_Co(Co);
    tiling.set_Kh(Kh);
    tiling.set_Kw(Kw);
    tiling.set_Ho(Ho);
    tiling.set_Wo(Wo);
    tiling.set_tileW(tileW);
    tiling.set_blockDim(blockDim);
    tiling.set_strideH(sH);
    tiling.set_strideW(sW);
    tiling.set_padTop(pT);
    tiling.set_padLeft(pL);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

